/**
 * Generate Google Maps firewall config.
 *
 * Data source: https://developers.google.com/maps/documentation
 *
 * Google Maps Platform authenticates with an API key passed as the
 * `key` query parameter on every request.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://developers.google.com/maps/documentation";
// Format: AIza + 35 chars (gitleaks: gcp-api-key)
const PLACEHOLDER_VALUE = "AIzaCoffeeSafeLocalCoffeeSafeLocalCoffe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Google Maps API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:google-maps",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const googleMapsFirewall = {",
    '  name: "google-maps",',
    '  description: "Google Maps Platform API",',
    "  placeholders: {",
    `    GOOGLE_MAPS_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://maps.googleapis.com",',
    "      auth: {",
    "        query: {",
    '          key: "${{ secrets.GOOGLE_MAPS_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Google Maps firewall config...");
  const ts = generateTypeScript();
  writeOutput("google-maps", ts, import.meta.dirname);
}
